        acs_url=os.environ.get("SP_ACS_URL", "http://localhost:8000/saml/acs"),
        audience=os.environ.get("SP_AUDIENCE", "https://sp.example.com/metadata"),
        require_signed_response_or_assertion=True,
        require_in_response_to=True,
